import { useState, useEffect } from "react";
import AdminLayout from "../../AdminLayout";
import "./AddPatient.css";

const countryCityMap = {
  India: ["Delhi", "Mumbai", "Bangalore", "Chennai"],
  UAE: ["Dubai", "Abu Dhabi", "Sharjah"],
  USA: ["New York", "Chicago"],
};

const countryCodes = [
  { code: "+91", name: "India" },
  { code: "+971", name: "UAE" },
  { code: "+1", name: "USA" },
  { code: "+44", name: "UK" },
  { code: "+61", name: "Australia" },
];

export default function AddPatient() {
  const [dob, setDob] = useState("");
  const [age, setAge] = useState("");
  const [country, setCountry] = useState("");
  const [cityList, setCityList] = useState([]);
  const [photo, setPhoto] = useState(null);

  const [countryCode, setCountryCode] = useState("+91");
  const [emgCountryCode, setEmgCountryCode] = useState("+91");

  const [patientIdNumber, setPatientIdNumber] = useState("");
  const [emergencyIdNumber, setEmergencyIdNumber] = useState("");

  const [patientIdExpiry, setPatientIdExpiry] = useState("");
  const [emergencyIdExpiry, setEmergencyIdExpiry] = useState("");

  useEffect(() => {
    if (!dob) return;
    const birth = new Date(dob);
    const today = new Date();
    let a = today.getFullYear() - birth.getFullYear();
    const m = today.getMonth() - birth.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) a--;
    setAge(a);
  }, [dob]);

  const handleCountryChange = (value) => {
    setCountry(value);
    setCityList(countryCityMap[value] || []);
  };

  const handleScan = (type) => {
    const fakeId = Math.floor(100000000000 + Math.random() * 900000000000);
    if (type === "patient") setPatientIdNumber(fakeId);
    if (type === "emergency") setEmergencyIdNumber(fakeId);
  };

  return (
    <AdminLayout>
      <div className="patient-page">

        {/* HEADER */}
        <div className="patient-header">
          <div>
            <h2>Patient Registration</h2>
            <p>HL7 • ADT A04</p>
          </div>

          <div className="photo-box">
            {photo ? <img src={photo} alt="" /> : <span>Upload Photo</span>}
            <input
              type="file"
              accept="image/*"
              capture="environment"
              onChange={(e) =>
                setPhoto(URL.createObjectURL(e.target.files[0]))
              }
            />
          </div>
        </div>

        <div className="patient-card">

          {/* ================= PATIENT IDENTIFICATION ================= */}
          <section>
            <h3>Patient Identification</h3>
            <div className="grid">

              <div>
                <label>ID Type</label>
                <select>
                  <option>Aadhaar Card</option>
                  <option>PAN Card</option>
                  <option>Voter ID</option>
                  <option>Passport</option>
                  <option>Driving License</option>
                </select>
              </div>

              <div>
                <label>ID Number</label>
                <input value={patientIdNumber} />
              </div>

              <div>
                <label>ID Expiry Date</label>
                <input
                  type="date"
                  value={patientIdExpiry}
                  onChange={(e) => setPatientIdExpiry(e.target.value)}
                />
              </div>

              <div>
                <label>Scan ID</label>
                <button
                  type="button"
                  className="scan-btn"
                  onClick={() => handleScan("patient")}
                >
                  Scan ID Card
                </button>
              </div>

            </div>
          </section>

          {/* ================= EMERGENCY ================= */}
          <section>
            <h3>Emergency Contact</h3>
            <div className="grid">

              <div>
                <label>First Name</label>
                <input />
              </div>

              <div>
                <label>Last Name</label>
                <input />
              </div>

              <div>
                <label>Relationship</label>
                <select>
                  <option>Father</option>
                  <option>Mother</option>
                  <option>Spouse</option>
                  <option>Brother</option>
                  <option>Sister</option>
                </select>
              </div>

              <div>
                <label>Country Code</label>
                <select
                  value={emgCountryCode}
                  onChange={(e) => setEmgCountryCode(e.target.value)}
                >
                  {countryCodes.map((c) => (
                    <option key={c.code} value={c.code}>
                      {c.name} ({c.code})
                    </option>
                  ))}
                </select>
              </div>

              <div>
                <label>Mobile Number</label>
                <input />
              </div>

              <div>
                <label>ID Type</label>
                <select>
                  <option>Aadhaar</option>
                  <option>PAN</option>
                  <option>Voter ID</option>
                </select>
              </div>

              <div>
                <label>ID Number</label>
                <input value={emergencyIdNumber} />
              </div>

              <div>
                <label>ID Expiry Date</label>
                <input
                  type="date"
                  value={emergencyIdExpiry}
                  onChange={(e) => setEmergencyIdExpiry(e.target.value)}
                />
              </div>

              <div>
                <label>Scan ID</label>
                <button
                  type="button"
                  className="scan-btn"
                  onClick={() => handleScan("emergency")}
                >
                  Scan ID
                </button>
              </div>

            </div>
          </section>

          <div className="actions">
            <button className="submit">Register Patient</button>
          </div>

        </div>
      </div>
    </AdminLayout>
  );
}
